#include <iostream> // Для ввода и вывода данных
#include <vector>   // Для использования контейнера vector

using namespace std; // Использование стандартного пространства имен

/**
 * @brief Вводит элементы целочисленного вектора с клавиатуры.
 *
 * @param vec Ссылка на вектор, который будет заполнен введенными пользователем значениями.
 *
 * @details
 * Функция запрашивает у пользователя количество элементов вектора,
 * затем последовательно считывает указанное количество целых чисел
 * и добавляет их в конец вектора с помощью метода push_back().
 */
void inputVector(vector<int>& vec);

/**
 * @brief Выполняет обработку вектора путем вставки числа -1 после каждого элемента.
 *
 * @param vec Ссылка на вектор, элементы которого будут изменены.
 *
 * @details
 * Функция проходит по вектору с помощью итератора и после каждого исходного
 * элемента вставляет значение -1. После вставки итератор сдвигается так,
 * чтобы не обрабатывать вставленный элемент повторно.
 */
void processVector(vector<int>& vec);

/**
 * @brief Выводит элементы вектора на экран.
 *
 * @param vec Константная ссылка на вектор, который необходимо вывести.
 *
 * @details
 * Функция не изменяет содержимое вектора, поэтому параметр передается
 * как константная ссылка. Элементы выводятся в одну строку через пробел.
 */
void displayVector(const vector<int>& vec);

/**
 * @brief Выводит разделительную линию на экран.
 *
 * @details
 * Функция используется для визуального оформления вывода программы.
 * Она печатает строку из символов "=".
 */
void printSeparator();

/**
 * @brief Главная функция программы.
 *
 * @return Код завершения программы:
 *         0 — программа завершена успешно.
 *
 * @details
 * Главная функция управляет выполнением всей программы.
 *
 * Алгоритм работы:
 * 1. Создается пустой вектор целых чисел.
 * 2. Выводится заголовок программы.
 * 3. Пользователь вводит количество элементов и сами элементы.
 * 4. На экран выводится исходный вектор.
 * 5. После каждого элемента вектора вставляется число -1.
 * 6. На экран выводится измененный вектор.
 * 7. Выводится информация о количестве элементов и вставок.
 * 8. Программа завершается с кодом 0.
 */
int main() {

    vector<int> numbers;  // Используем стандартный класс vector для хранения чисел
    
    printSeparator(); // Вывод разделительной линии

    cout << "    Работа с вектором целых чисел" << endl; // Вывод заголовка программы

    printSeparator(); // Повторный вывод разделительной линии
    
    inputVector(numbers); // Вызов функции ввода элементов
    
    cout << "\nИсходный вектор: "; // Вывод текста перед отображением вектора

    displayVector(numbers); // Вывод исходного вектора
    
    cout << "\nВставка -1 после каждого элемента..." << endl; // Сообщение о начале обработки

    processVector(numbers); // Вызов функции обработки вектора
    
    cout << "Результат: "; // Вывод текста перед результатом

    displayVector(numbers); // Вывод измененного вектора
    
    cout << "\nИнформация об операции:" << endl; // Заголовок блока информации

    cout << "Исходное количество элементов: " << numbers.size() / 2 << endl; // Вывод исходного размера

    cout << "Результирующий размер: " << numbers.size() << endl; // Вывод нового размера

    cout << "Количество вставок: " << numbers.size() / 2 << endl; // Вывод количества вставленных элементов
    
    printSeparator(); // Вывод разделительной линии

    cout << "Программа успешно завершена" << endl; // Сообщение об успешном завершении
    
    return 0; // Успешное завершение программы
}

/**
 * @brief Вводит элементы вектора с клавиатуры.
 *
 * @param vec Ссылка на вектор, в который будут добавлены введенные элементы.
 *
 * @details
 * Сначала функция запрашивает количество элементов n.
 * Затем с помощью цикла for пользователь вводит n целых чисел.
 * Каждое введенное число сохраняется во временной переменной value
 * и добавляется в конец вектора методом push_back().
 *
 * Вектор передается по ссылке, поэтому все добавленные элементы
 * сохраняются в исходном объекте, переданном из функции main().
 */
void inputVector(vector<int>& vec) {

    int n, value; // n - количество элементов, value - временная переменная для ввода
    
    cout << "Введите количество элементов: "; // Запрос количества элементов

    cin >> n; // Ввод количества элементов
    
    cout << "Введите " << n << " целых чисел через пробел: "; // Запрос ввода элементов

    for (int i = 0; i < n; i++) { // Цикл ввода элементов

        cin >> value; // Ввод очередного элемента

        vec.push_back(value); // Добавление элемента в конец вектора
    }
}

/**
 * @brief Вставляет число -1 после каждого элемента вектора.
 *
 * @param vec Ссылка на вектор, который необходимо обработать.
 *
 * @details
 * Функция использует итератор для последовательного прохода по вектору.
 * После каждого текущего элемента вставляется значение -1.
 *
 * Метод insert() вставляет элемент в указанную позицию и возвращает
 * итератор на вставленный элемент. После вставки выполняется переход
 * к следующему элементу, чтобы продолжить обработку именно исходных
 * элементов вектора, а не добавленных значений -1.
 *
 * Пример:
 * исходный вектор: 1 2 3
 * после обработки: 1 -1 2 -1 3 -1
 */
void processVector(vector<int>& vec) {

    auto i = vec.begin(); // Итератор указывает на первый элемент вектора
    
    while (i != vec.end()) { // Цикл выполняется, пока итератор не достигнет конца вектора

        i = vec.insert(i + 1, -1); // Вставка -1 после текущего элемента
        
        ++i; // Переход к следующему исходному элементу
    }
}

/**
 * @brief Выводит содержимое вектора на экран.
 *
 * @param vec Константная ссылка на вектор, элементы которого нужно вывести.
 *
 * @details
 * Функция использует цикл range-based for для перебора всех элементов.
 * Каждый элемент выводится в консоль через пробел.
 *
 * Параметр vec является константной ссылкой, потому что функция
 * только читает данные и не должна изменять содержимое вектора.
 */
void displayVector(const vector<int>& vec) {

    for (int value : vec) { // Цикл перебора всех элементов вектора

        cout << value << " "; // Вывод текущего элемента
    }

    cout << endl; // Переход на новую строку
}

/**
 * @brief Выводит разделительную линию.
 *
 * @details
 * Функция предназначена для оформления консольного вывода.
 * Она помогает визуально отделять разные части программы:
 * заголовок, результат и сообщение о завершении.
 */
void printSeparator() {

    cout << "========================================" << endl; // Вывод линии-разделителя
}
